import json
import os
import subprocess
import sys
from pathlib import Path

from _enrich_helper import repo_root

AC_UID = "99088d48c256770f"
AC_TYPE = "data"

_ENRICH = repo_root() / "scripts" / "graphify-enrich.py"


def _run(project_dir: Path, args: list[str], env_extra: dict) -> subprocess.CompletedProcess:
    env = dict(os.environ)
    env["CLAUDE_PROJECT_DIR"] = str(project_dir)
    env.update(env_extra)
    return subprocess.run(
        [sys.executable, str(_ENRICH)] + args,
        capture_output=True, text=True, env=env, timeout=120,
    )


def test_AC_A8(tmp_path):
    r"""
    GIVEN: the advisory fail-open paths of graphify-enrich.py (branch-split per codex #3 / #8: the disabled branch :230-235 returns 0 WITHOUT calling _patch_context, so it emits no graph_context; the nil-map :241-248, unavailable :257-263, and builder-exception branches DO call _patch_context; and _patch_conte...
    WHEN:  graphify-enrich.py main() runs on each fail-open branch
    THEN:  (i) DISABLED branch (--no-graphify or CLAUDE_GRAPHIFY_ENABLED=0): exit 0 and the existing no-patch behavior is preserved (graph_context ABSENT is acceptable; the AC does NOT require advisory:True here). (ii) NIL-MAP / UNAVAILABLE / BUILDER-EXCEPTION branches WITH an existing --context-file: exit 0 AND the patched context-file's graph_context.advisory == True (empty_graph_context sets advisory:True, graphify_lib.py:474). WITHOUT a --context-file (or it does not exist): exit-0 / never-block is sufficient and no graph_context is written. Old fields stay valid; DEV is never blocked on any branch.
    """
    project = tmp_path / "proj"
    project.mkdir()

    # --- (i) DISABLED branch: --no-graphify, with a context-file present ---
    ctx_disabled = project / "context-disabled.json"
    ctx_disabled.write_text(json.dumps({"task_id": "t1"}), encoding="utf-8")
    r = _run(project, ["--task-id", "t1", "--context-file", str(ctx_disabled), "--no-graphify"], {})
    assert r.returncode == 0
    # No graph_context patched on the disabled branch (no-patch behavior preserved).
    assert "graph_context" not in json.loads(ctx_disabled.read_text(encoding="utf-8"))

    # --- (ii) NIL-MAP branch WITH an existing --context-file ---
    # No blast-radius-map.json under dev-registry -> status=skipped, calls _patch_context.
    ctx_nil = project / "context-nil.json"
    ctx_nil.write_text(json.dumps({"task_id": "t2"}), encoding="utf-8")
    r2 = _run(project, ["--task-id", "t2", "--context-file", str(ctx_nil)],
              {"CLAUDE_GRAPHIFY_ENABLED": "1"})
    assert r2.returncode == 0
    patched = json.loads(ctx_nil.read_text(encoding="utf-8"))
    assert patched["graph_context"]["advisory"] is True

    # --- (ii) NIL-MAP branch WITHOUT a --context-file: exit-0, never blocks ---
    r3 = _run(project, ["--task-id", "t3"], {"CLAUDE_GRAPHIFY_ENABLED": "1"})
    assert r3.returncode == 0
